example.com {
    @nsfw_needverify  cookie_json nsfwCookie needVerify true
    @nsfw_verified    cookie_json nsfwCookie verified   true
    @plan_pro         header_json X-Session plan.tier pro enterprise
    @flag0_gate       cookie_json nsfwCookie flags.0.kind gate

    @num_src          cookie_json numCookie n 1e3
    @num_src_dotzero  cookie_json numCookie n 1.0
    @num_src_trail    cookie_json numCookie n 1.50
    @plus_tok         cookie_json plusCookie tok a+b
    @dup_last         cookie_json dupCookie k b
    @deep_shallow     cookie_json deepCookie shallow yes

    classify {needVerify} {
        when cookie_json nsfwCookie needVerify false -> 0
        when @nsfw_needverify                        -> 1
        default                                      -> 0
    }
    classify {nsfwVerified} {
        when @nsfw_verified -> 1
        default             -> 0
    }

    pass @plan_pro

    cache_key host path {needVerify} {nsfwVerified}

    header NEEDVERIFY   {classify.needVerify}
    header NSFWVERIFIED {classify.nsfwVerified}
    header @flag0_gate X-Flag0-Gate 1
    header @num_src         X-Num-Src 1
    header @num_src_dotzero X-Num-DotZero 1
    header @num_src_trail   X-Num-Trail 1
    header @plus_tok        X-Plus-Tok 1
    header @dup_last        X-Dup-Last 1
    header @deep_shallow    X-Deep-Shallow 1
}
